def get_colliding_boxes(bboxes):
    colliding_pairs = []
    for i, box_a in enumerate(bboxes):
        for j, box_b in enumerate(bboxes[i + 1:], start=i + 1):
            if box_a.intersects(box_b):
                colliding_pairs.append((box_a, box_b))
    return colliding_pairs

